import{_ as l,o as i,c as e,a2 as t}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"2008年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2008年/核心总结.md","filePath":"01_letters/2008年/核心总结.md"}'),o={name:"01_letters/2008年/核心总结.md"};function r(u,a,h,n,q,d){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="_2008年巴菲特致股东信核心总结" tabindex="-1">2008年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2008年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2008年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净资产减少115亿美元，每股账面价值下降9.6%</li><li>44年来最糟糕的一年，但跑赢标普500指数27.4个百分点</li><li>标普500下跌37%，伯克希尔展现防御性</li></ul><h2 id="时代背景" tabindex="-1">时代背景 <a class="header-anchor" href="#时代背景" aria-label="Permalink to &quot;时代背景&quot;">​</a></h2><h3 id="金融危机" tabindex="-1">金融危机 <a class="header-anchor" href="#金融危机" aria-label="Permalink to &quot;金融危机&quot;">​</a></h3><ul><li>信贷市场功能失调，&quot;整个国家都信奉：我们信仰上帝；其他人现金结账&quot;</li><li>政府大规模干预：财政部和美联储&quot;all in&quot;</li><li>伯克希尔在危机最顶峰向商业世界投入155亿美元</li></ul><h3 id="伯克希尔的应对" tabindex="-1">伯克希尔的应对 <a class="header-anchor" href="#伯克希尔的应对" aria-label="Permalink to &quot;伯克希尔的应对&quot;">​</a></h3><ul><li>90亿美元支持三家美国企业（高盛、通用电气、箭牌）</li><li>65亿美元履行箭牌收购承诺</li><li>保持流动性供应者角色，而非求助者</li></ul><h2 id="主要投资决策" tabindex="-1">主要投资决策 <a class="header-anchor" href="#主要投资决策" aria-label="Permalink to &quot;主要投资决策&quot;">​</a></h2><h3 id="重大投资" tabindex="-1">重大投资 <a class="header-anchor" href="#重大投资" aria-label="Permalink to &quot;重大投资&quot;">​</a></h3><ol><li><p><strong>箭牌、高盛、通用电气固定收益证券</strong>：145亿美元</p><ul><li>高收益率 + 股权认购权</li><li>&quot;市场混乱给我们收购带来了顺风&quot;</li></ul></li><li><p><strong>完成Marmon收购</strong>：持股增至64%</p></li></ol><h3 id="投资错误承认" tabindex="-1">投资错误承认 <a class="header-anchor" href="#投资错误承认" aria-label="Permalink to &quot;投资错误承认&quot;">​</a></h3><ul><li><strong>康菲石油</strong>：油价接近峰值时大量买入，损失数十亿美元</li><li><strong>两家爱尔兰银行</strong>：2.44亿美元买入，年末价值2700万美元，亏损89%</li></ul><h3 id="被迫卖出" tabindex="-1">被迫卖出 <a class="header-anchor" href="#被迫卖出" aria-label="Permalink to &quot;被迫卖出&quot;">​</a></h3><ul><li>为资助大额投资，卖出强生、宝洁、康菲部分持仓</li><li>&quot;我宁愿放弃诱人机会也不愿意睡不着觉&quot;</li></ul><h2 id="关键理念" tabindex="-1">关键理念 <a class="header-anchor" href="#关键理念" aria-label="Permalink to &quot;关键理念&quot;">​</a></h2><h3 id="金融危机教训" tabindex="-1">金融危机教训 <a class="header-anchor" href="#金融危机教训" aria-label="Permalink to &quot;金融危机教训&quot;">​</a></h3><ul><li>&quot;许多大型金融机构经历了一系列威胁生命的问题&quot;</li><li>衍生品带来杠杆和风险，使大银行无法理解自己</li><li>房地美、房利美案例显示监管失效</li></ul><h3 id="衍生品风险" tabindex="-1">衍生品风险 <a class="header-anchor" href="#衍生品风险" aria-label="Permalink to &quot;衍生品风险&quot;">​</a></h3><ul><li>伯克希尔有251份衍生品合约</li><li>持有资金，无对手方风险</li><li>长期股票看跌期权：布莱克-斯科尔斯公式给出荒谬定价</li></ul><h3 id="住房抵押贷款" tabindex="-1">住房抵押贷款 <a class="header-anchor" href="#住房抵押贷款" aria-label="Permalink to &quot;住房抵押贷款&quot;">​</a></h3><ul><li>克莱顿198,888名借款人表现良好</li><li>关键：收入核实、合理首付、可负担月供</li><li>批评政府担保借款人比AAA公司更有资金优势</li></ul><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><ul><li>浮存金585亿美元，承保利润28亿美元</li><li>连续六年承保盈利</li><li>GEICO市场份额增至7.7%，成为第三大汽车保险公司</li></ul><h2 id="投资哲学" tabindex="-1">投资哲学 <a class="header-anchor" href="#投资哲学" aria-label="Permalink to &quot;投资哲学&quot;">​</a></h2><h3 id="市场态度" tabindex="-1">市场态度 <a class="header-anchor" href="#市场态度" aria-label="Permalink to &quot;市场态度&quot;">​</a></h3><ul><li>&quot;悲观是你的朋友，乐观是敌人&quot;</li><li>&quot;不管买袜子还是股票，我都喜欢降价买优质商品&quot;</li><li>价格下跌让我们能买到好东西</li></ul><h3 id="现金策略" tabindex="-1">现金策略 <a class="header-anchor" href="#现金策略" aria-label="Permalink to &quot;现金策略&quot;">​</a></h3><ul><li>保持200多亿美元现金等价物</li><li>&quot;我们永远不会依赖陌生人的善意&quot;</li><li>&quot;&#39;大到不能倒&#39;不是伯克希尔的退路&quot;</li></ul><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;投资世界现在从低估风险变成了高估风险。&quot;</p></blockquote><blockquote><p>&quot;获得认可不是投资目标。受欢迎的投资决策往往最后不被接受。&quot;</p></blockquote><blockquote><p>&quot;美国从来不缺挑战，我们也从来没有克服不了挑战。&quot;</p></blockquote><blockquote><p>&quot;不管你喜不喜欢，华尔街、主街、美国各种大街小巷，所有人都在同一条船上。&quot;</p></blockquote><hr><p><em>生成日期：2026年4月</em></p>',36)])])}const b=l(o,[["render",r]]);export{c as __pageData,b as default};
